<?php
namespace Tests\Feature;use App\Models\Document;use App\Models\Employee;use App\Models\Role;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Storage;use Laravel\Sanctum\Sanctum;use Tests\TestCase;
class DocumentSecurityTest extends TestCase{use RefreshDatabase;public function test_employee_can_download_only_own_document():void{Storage::fake('local');$role=Role::create(['name'=>'Employee','slug'=>'employee','permissions'=>['document.self'],'is_active'=>true]);[$u1,$e1]=$this->employee($role);[$u2,$e2]=$this->employee($role);Storage::disk('local')->put('employee-documents/test.pdf','content');$own=Document::create(['employee_id'=>$e1->id,'title'=>'Own','file_path'=>'employee-documents/test.pdf','file_name'=>'test.pdf','file_size'=>7,'mime_type'=>'application/pdf','document_type'=>'contract','storage_disk'=>'local']);$other=Document::create(['employee_id'=>$e2->id,'title'=>'Other','file_path'=>'employee-documents/test.pdf','file_name'=>'test.pdf','file_size'=>7,'mime_type'=>'application/pdf','document_type'=>'contract','storage_disk'=>'local']);Sanctum::actingAs($u1);$this->get("/api/documents/{$own->id}/download")->assertOk();$this->getJson("/api/documents/{$other->id}/download")->assertForbidden();}private function employee(Role$r):array{$u=User::factory()->create(['role_id'=>$r->id,'is_active'=>true]);$e=Employee::create(['user_id'=>$u->id,'joining_date'=>now(),'employment_type'=>'full-time','salary'=>0]);return[$u,$e];}}
